1	export interface ItemSpec {
2	  type: string;
3	}
4	
5	export interface Customer {
6	  yearsWithMHPCO: number;
7	}
8	
9	export interface QuoteInput {
10	  customer: Customer;
11	  items: ItemSpec[];
12	}
13	
14	export interface QuoteResult {
15	  premium: number;
16	}
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	};
28	
29	function basePremiumFor(item: ItemSpec): number {
30	  return BASE_PREMIUMS[item.type] ?? 0;
31	}
32	
33	export function quote(input: QuoteInput): QuoteResult {
34	  const policyBasePremium = input.items.reduce(
35	    (sum, item) => sum + basePremiumFor(item),
36	    0
37	  );
38	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
39	  return {
40	    premium: policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
41	  };
42	}
43	
44	export function claim(): unknown {
45	  return undefined;
46	}
